import{_ as i,o as s,c as l,ag as e}from"./chunks/framework.DNt_9s2P.js";const k=JSON.parse('{"title":"インストール","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install.md","filePath":"guide/install.md"}'),t={name:"guide/install.md"};function n(o,a,r,h,p,d){return s(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="インストール" tabindex="-1">インストール <a class="header-anchor" href="#インストール" aria-label="Permalink to &quot;インストール&quot;">​</a></h1><h2 id="ダウンロード" tabindex="-1">ダウンロード <a class="header-anchor" href="#ダウンロード" aria-label="Permalink to &quot;ダウンロード&quot;">​</a></h2><p><a href="https://github.com/mirai-mamori/Selah/releases/latest" target="_blank" rel="noreferrer">最新リリース</a> から、お使いの OS に合ったインストーラーをダウンロードしてください。</p><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li><code>.dmg</code> ファイルをダウンロード</li><li>ダウンロードした <code>.dmg</code> を開き、<code>Selah.app</code> を <code>Applications</code> フォルダにドラッグ</li><li>初回起動時に「開発元が確認できない」と表示される場合は、<strong>システム設定 &gt; プライバシーとセキュリティ</strong> から「このまま開く」を選択</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>macOS 11 Big Sur 以降が必要です。Apple Silicon (M1/M2/M3/M4) と Intel の両方に対応しています。</p></div><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li><code>.exe</code> (NSIS インストーラー) をダウンロード</li><li>インストーラーを実行し、指示に従ってインストール</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Windows 10 または Windows 11 が必要です。WebView2 ランタイムが自動的にインストールされます。</p></div><h2 id="初回セットアップ" tabindex="-1">初回セットアップ <a class="header-anchor" href="#初回セットアップ" aria-label="Permalink to &quot;初回セットアップ&quot;">​</a></h2><ol><li>Selah を起動すると、ログイン画面が表示されます</li><li>関西学院大学の SSO アカウント（利用者 ID とパスワード）でログインします</li><li>ログインが完了すると、KWIC・Luna・メールのデータが自動的に取得されます</li></ol><h2 id="ai-機能のセットアップ-任意" tabindex="-1">AI 機能のセットアップ（任意） <a class="header-anchor" href="#ai-機能のセットアップ-任意" aria-label="Permalink to &quot;AI 機能のセットアップ（任意）&quot;">​</a></h2><p>AI 機能（履修分析・学習計画・通知サマリー）を使用するには、別途 API キーの設定が必要です。</p><ol><li>トレイアイコンまたは設定画面から <strong>AI 設定</strong> を開く</li><li><strong>OpenAI API Key</strong> または <strong>Google Gemini API Key</strong> を入力</li><li>使用するモデルを選択して保存</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>API キーはローカルのキーチェーン（macOS）またはクレデンシャルストア（Windows）に安全に保存されます。</p></div><h2 id="ビルド-開発者向け" tabindex="-1">ビルド（開発者向け） <a class="header-anchor" href="#ビルド-開発者向け" aria-label="Permalink to &quot;ビルド（開発者向け）&quot;">​</a></h2><p>ソースからビルドする場合：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 依存関係のインストール</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 開発モードで起動</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tauri</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># リリースビルド</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tauri</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h3 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h3><ul><li>Node.js 18+</li><li>Rust 1.70+</li><li><a href="https://tauri.app/start/prerequisites/" target="_blank" rel="noreferrer">Tauri 2 の前提条件</a></li></ul>`,20)])])}const u=i(t,[["render",n]]);export{k as __pageData,u as default};
